{
  "family": "Ritter Reaction",
  "candidate": {
    "substrate_smiles": [
      "CC(C)(C)O",
      "CC#N"
    ],
    "product_smiles": [
      "CC(=O)NC(C)(C)C"
    ],
    "optional_reagent_smiles": [
      "O=S(=O)(O)O"
    ],
    "rationale": "This is a classic textbook example of the Ritter reaction, demonstrating the formation of a stable tert-butyl carbocation from tert-butanol under strong acid (H2SO4) conditions. This carbocation is then trapped by a simple nitrile, acetonitrile, which after hydrolysis yields the corresponding N-tert-butylacetamide. All components are simple, acyclic, and clearly illustrate the core transformation of the Ritter reaction: carbocation + nitrile -> N-substituted amide.",
    "collision_avoidance_note": "This example uses simple, acyclic, non-aromatic substrates (tert-butanol and acetonitrile) to avoid overlap with reactions involving aromatic rings, rearrangements, or other complex functional groups. The use of a tertiary alcohol as the carbocation precursor is a common and specific feature of the Ritter reaction, distinguishing it from other nitrile addition reactions."
  }
}
